abstract class Shape {
    String color;
    abstract double area();  // no body — subclasses must provide it

    void describe() {
        System.out.println(color + " shape, area = " + area());
    }
}

class Circle extends Shape {
    double r;
    Circle(String c, double r) { this.color = c; this.r = r; }
    double area() { return 3.14159 * r * r; }
}

class Rectangle extends Shape {
    double w, h;
    Rectangle(String c, double w, double h) { this.color = c; this.w = w; this.h = h; }
    double area() { return w * h; }
}

new Circle("red", 5).describe();      // red shape, area = 78.53975
